#!/usr/bin/env node
/**
 * Compile the private JSON compendium sources into distributable LevelDB packs.
 *
 * This script deliberately never reads source data from Git and never writes to
 * the live ./packs directory.  It is safe to use for release staging while a
 * development checkout remains installed in Foundry (Foundry itself must still
 * be closed while creating a release).
 *
 * Prerequisites:
 *   - private _source/ directory generated by the maintainer's import scripts
 *   - a local Foundry desktop installation (the same installation that runs this system)
 *     or Foundry's official CLI available as `fvtt`
 *
 * Usage:
 *   node tools/build-compendia.mjs
 *   node tools/build-compendia.mjs --generate
 *   node tools/build-compendia.mjs --output C:\\release-staging\\packs
 *   node tools/build-compendia.mjs --engine cli
 */
import { existsSync, mkdirSync, readdirSync, rmSync, readFileSync } from "node:fs";
import { resolve, join, dirname } from "node:path";
import { spawnSync } from "node:child_process";
import process from "node:process";
import { fileURLToPath, pathToFileURL } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const sourceRoot = join(root, "_source");
const defaultOutput = join(root, "dist", "staging", "packs");

const packSources = {
  effects: "effects",
  weapons: "pack-weapons",
  armors: "pack-armors",
  vehicles: "pack-vehicles",
  items: "pack-items",
  dlois: "pack-dlois",
  works: "pack-works",
  syndromes: "pack-syndromes"
};

function parseArgs(argv) {
  let output = defaultOutput;
  let engine = "auto";
  let generate = false;
  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === "--output") output = resolve(argv[++i] ?? "");
    else if (argv[i] === "--generate") generate = true;
    else if (argv[i] === "--engine") {
      engine = argv[++i] ?? "";
      if (!["auto", "cli", "foundry"].includes(engine)) throw new Error("--engine must be auto, cli, or foundry");
    }
    else if (argv[i] === "--help" || argv[i] === "-h") {
      console.log("Usage: node tools/build-compendia.mjs [--generate] [--output <packs-directory>] [--engine auto|cli|foundry]");
      process.exit(0);
    } else throw new Error(`Unknown argument: ${argv[i]}`);
  }
  return { output, engine, generate };
}

function assertSource(path, pack) {
  if (!existsSync(path)) throw new Error(`Private source for '${pack}' is missing: ${path}`);
  const jsonCount = readdirSync(path, { withFileTypes: true })
    .filter(entry => entry.isFile() && entry.name.endsWith(".json")).length;
  if (!jsonCount) throw new Error(`Private source for '${pack}' contains no JSON documents: ${path}`);
  return jsonCount;
}

const { output, engine, generate } = parseArgs(process.argv.slice(2));
if (!existsSync(sourceRoot)) throw new Error(`Private _source directory is required: ${sourceRoot}`);

if (generate) {
  // These generators remain private because their inputs and curation data are
  // private. Their outputs are the JSON documents packed below.
  for (const script of ["build-effects.mjs", "build-items.mjs", "build-dlois.mjs", "build-core-character-data.mjs"]) {
    const path = join(sourceRoot, script);
    if (!existsSync(path)) throw new Error(`Private generator is missing: ${path}`);
    console.log(`DX3rd | generating source: ${script}`);
    const result = spawnSync(process.execPath, [path], { cwd: root, stdio: "inherit" });
    if (result.error) throw new Error(`Could not start ${script}: ${result.error.message}`);
    if (result.status !== 0) throw new Error(`${script} failed (exit ${result.status}).`);
  }
}

const fvtt = process.platform === "win32" ? "fvtt.cmd" : "fvtt";
const cliCheck = process.platform === "win32"
  ? spawnSync("where.exe", [fvtt], { stdio: "ignore" })
  : spawnSync("which", [fvtt], { stdio: "ignore" });
const hasCli = !cliCheck.error && cliCheck.status === 0;
const foundryApp = process.env.FOUNDRY_APP_PATH || "C:/Program Files/Foundry Virtual Tabletop/resources/app";
const classicLevelPath = join(foundryApp, "node_modules", "classic-level", "index.js");
const hasFoundryDatabase = existsSync(classicLevelPath);
const selectedEngine = engine === "auto" ? (hasCli ? "cli" : "foundry") : engine;
if (selectedEngine === "cli" && !hasCli) {
  throw new Error("Foundry CLI was not found. Install it with: npm install -g @foundryvtt/foundryvtt-cli");
}
if (selectedEngine === "foundry" && !hasFoundryDatabase) {
  throw new Error(`Foundry's ClassicLevel dependency was not found: ${classicLevelPath}. Set FOUNDRY_APP_PATH or install the Foundry CLI.`);
}

let ClassicLevel;
if (selectedEngine === "foundry") ({ ClassicLevel } = await import(pathToFileURL(classicLevelPath).href));

async function packWithFoundry(pack, input) {
  const destination = join(output, pack);
  const docs = readdirSync(input)
    .filter(name => name.endsWith(".json"))
    .sort()
    .map(name => JSON.parse(readFileSync(join(input, name), "utf8")));
  for (const doc of docs) {
    if (!doc._key) throw new Error(`${pack}: document '${doc.name ?? doc._id ?? "unknown"}' has no _key`);
  }
  rmSync(destination, { recursive: true, force: true });
  const db = new ClassicLevel(destination, { valueEncoding: "json" });
  await db.open();
  try {
    await db.batch(docs.map(doc => ({ type: "put", key: doc._key, value: doc })));
  } finally {
    await db.close();
  }
  // LOCK and LOG are process-local LevelDB runtime artifacts. They are not
  // pack data and would cause needless diffs after each Foundry launch.
  for (const transient of ["LOCK", "LOG", "LOG.old"]) {
    rmSync(join(destination, transient), { force: true });
  }
}

// Build into a disposable staging directory. Never mutate the checkout's
// installed packs: it avoids LevelDB churn and prevents a half-built release
// from affecting a running development world.
rmSync(output, { recursive: true, force: true });
mkdirSync(output, { recursive: true });

for (const [pack, sourceDirectory] of Object.entries(packSources)) {
  const input = join(sourceRoot, sourceDirectory);
  const count = assertSource(input, pack);
  console.log(`DX3rd | packing ${pack} (${count} JSON documents; ${selectedEngine})`);
  if (selectedEngine === "foundry") await packWithFoundry(pack, input);
  else {
    const result = spawnSync(fvtt, [
      "package", "pack", "-n", pack,
      "--inputDirectory", input,
      "--outputDirectory", output
    ], { cwd: root, stdio: "inherit", shell: process.platform === "win32" });
    if (result.error) throw new Error(`Could not start '${fvtt}': ${result.error.message}`);
    if (result.status !== 0) throw new Error(`Packing '${pack}' failed (exit ${result.status}).`);
  }
}

console.log(`DX3rd | compendium build complete: ${output}`);
